func evidence_httpproto_resource_cleanup_proof_11vse2(elapsedMs int, absoluteBudgetMs int, bufferedBytes int, byteBudget int, queueDepth int) (bool, string) {
	admit, reason := elapsedMs <= absoluteBudgetMs, "time"
	if bufferedBytes > byteBudget { admit, reason = false, "memory" }
	if queueDepth > 32 { admit, reason = false, "backpressure" }
	if absoluteBudgetMs <= 0 || byteBudget <= 0 { admit, reason = false, "invalid-budget" }
